// Calcular KPIs del resumen ejecutivo para el email
const items = $input.all();
const procesadas = items.filter(i => i.json.estado_procesado === 'procesado');

const total = procesadas.length;
const positivos = procesadas.filter(i => i.json.sentimiento === 'positivo').length;
const negativos = procesadas.filter(i => i.json.sentimiento === 'negativo').length;
const alertas   = procesadas.filter(i => Number(i.json.score_urgencia) >= 4).length;

const ratings = procesadas
  .map(i => parseFloat(i.json.calificacion_estrella))
  .filter(r => !isNaN(r) && r > 0);

const avgRating = ratings.length > 0
  ? (ratings.reduce((a, b) => a + b, 0) / ratings.length).toFixed(1)
  : null;

const promotores  = ratings.filter(r => r === 5).length;
const detractores = ratings.filter(r => r <= 2).length;
const nps = ratings.length > 0
  ? Math.round(((promotores - detractores) / ratings.length) * 100)
  : null;

const tasaPositiva = total > 0 ? Math.round((positivos / total) * 100) : 0;

// Semana actual
const hoy    = new Date();
const lunes  = new Date(hoy);
lunes.setDate(hoy.getDate() - hoy.getDay() + 1);
const domingo = new Date(lunes);
domingo.setDate(lunes.getDate() + 6);
const semana = `${lunes.toLocaleDateString('es-CO')} – ${domingo.toLocaleDateString('es-CO')}`;

// Top categorías negativas
const catNeg = {};
processadas.filter(i => i.json.sentimiento === 'negativo').forEach(i => {
  const cat = i.json.categoria || 'otro';
  catNeg[cat] = (catNeg[cat] || 0) + 1;
});
const topNeg = Object.entries(catNeg)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([cat, n]) => `${cat} (${n})`);

// Alertas críticas para el email
const alertasDetalle = procesadas
  .filter(i => Number(i.json.score_urgencia) >= 4)
  .sort((a, b) => Number(b.json.score_urgencia) - Number(a.json.score_urgencia))
  .slice(0, 5)
  .map(i => ({
    resumen:  i.json.resumen_ia,
    accion:   i.json.accion_sugerida,
    categoria: i.json.categoria,
    score:    i.json.score_urgencia,
    fuente:   i.json.fuente
  }));

console.log(`[VOC Email] Total: ${total} | NPS: ${nps} | Alertas: ${alertas}`);

return [{
  json: {
    semana,
    total,
    positivos,
    negativos,
    tasaPositiva,
    nps,
    avgRating,
    alertas,
    topNeg,
    alertasDetalle,
    fecha: new Date().toLocaleDateString('es-CO', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
}];

