=<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<style>
body { font-family: Arial, sans-serif; background: #f4f4f4; margin: 0; padding: 0; }
.container { max-width: 620px; margin: 0 auto; background: white; }
.header { background: #6C5CE7; padding: 32px 30px; }
.header h1 { color: white; margin: 0; font-size: 24px; }
.header p { color: #DDD6FE; margin: 6px 0 0; font-size: 14px; }
.kpis { display: flex; padding: 24px 20px; gap: 12px; background: #f8f9fa; }
.kpi { flex: 1; text-align: center; background: white; border-radius: 8px; padding: 16px 8px; border: 1px solid #e0e0e0; }
.kpi .val { font-size: 28px; font-weight: bold; color: #4A3DB5; }
.kpi .lbl { font-size: 11px; color: #636e72; margin-top: 4px; }
.section { padding: 20px 30px; }
.section h2 { color: #4A3DB5; font-size: 15px; border-bottom: 2px solid #6C5CE7; padding-bottom: 6px; }
.alerta { background: #fff5f5; border-left: 4px solid #E24B4A; padding: 12px 16px; margin-bottom: 10px; border-radius: 4px; }
.alerta .cat { font-size: 11px; font-weight: bold; color: #E24B4A; text-transform: uppercase; }
.alerta .res { font-size: 13px; color: #2d3436; margin: 4px 0; }
.alerta .acc { font-size: 12px; color: #4A3DB5; font-weight: bold; }
.footer { background: #6C5CE7; padding: 16px 30px; text-align: center; }
.footer p { color: #DDD6FE; font-size: 11px; margin: 0; }
.btn { display: inline-block; background: white; color: #4A3DB5; padding: 10px 24px; border-radius: 6px; font-weight: bold; text-decoration: none; margin-top: 12px; font-size: 13px; }
</style>
</head>
<body>
<div class='container'>
  <div class='header'>
    <h1>📊 VOC Report Semanal</h1>
    <p>LOGYCA / LAB &nbsp;·&nbsp; {{ $json.semana }}</p>
  </div>

  <div class='kpis'>
    <div class='kpi'><div class='val'>{{ $json.total }}</div><div class='lbl'>Total reseñas</div></div>
    <div class='kpi'><div class='val'>{{ $json.nps !== null ? $json.nps : 'N/A' }}</div><div class='lbl'>NPS estimado</div></div>
    <div class='kpi'><div class='val'>{{ $json.tasaPositiva }}%</div><div class='lbl'>Tasa positiva</div></div>
    <div class='kpi'><div class='val' style='color: {{ $json.alertas > 0 ? "#E24B4A" : "#00B894" }}'>{{ $json.alertas }}</div><div class='lbl'>Alertas activas</div></div>
  </div>

  <div class='section'>
    <h2>Categorías con más menciones negativas</h2>
    <p style='color: #636e72; font-size: 13px;'>{{ $json.topNeg.length > 0 ? $json.topNeg.join(" &nbsp;·&nbsp; ") : "Sin menciones negativas esta semana ✓" }}</p>
  </div>

  {{ $json.alertas > 0 ? `
  <div class='section'>
    <h2>⚠ Alertas críticas — Acción requerida</h2>
    ${$json.alertasDetalle.map(a => `
    <div class='alerta'>
      <div class='cat'>${a.categoria} &nbsp;·&nbsp; Urgencia ${a.score}/5 &nbsp;·&nbsp; ${a.fuente}</div>
      <div class='res'>${a.resumen}</div>
      <div class='acc'>👉 ${a.accion}</div>
    </div>`).join('')}
  </div>` : `
  <div class='section'>
    <p style='color: #00B894; font-weight: bold;'>✓ Sin alertas críticas esta semana.</p>
  </div>` }}

  <div class='section' style='text-align: center; padding-bottom: 30px;'>
    <p style='color: #636e72; font-size: 13px;'>El reporte PDF completo con análisis detallado está disponible en el dashboard.</p>
    <a href='{{ $vars.DASHBOARD_URL || "#" }}' class='btn'>Ver dashboard completo →</a>
  </div>

  <div class='footer'>
    <p>VOC Pipeline · LOGYCA/LAB · Análisis automático con IA · {{ $json.fecha }}</p>
  </div>
</div>
</body>
</html>

